#include <unordered_set>

class MyCalendarThree {
public:
    MyCalendarThree() {}

    int book(int startTime, int endTime) {
        // Initialize a map to store the start times of booked events
        std::unordered_set<int> startTimes;

        // Add the start time to the map
        startTimes.insert(startTime);

        // Iterate from startTime to endTime
        for (int i = startTime; i <= endTime; i++) {
            // Check if there are k events with i as their start time
            int k = findK(i);

            // If k is greater than 0, return k; otherwise, return -1
            if (k > 0) {
                return k;
            }
        }

        // If no k events are found, return -1
        return -1;
    }

    int findK(int i) {
        // Find the maximum number of events with i as their start time
        int k = 0;

        // Iterate through the start times and check if i is in the set
        for (auto it = startTimes.begin(); it != startTimes.end(); ++it) {
            if (i == *it) {
                k++;
            }
        }

        return k;
    }
};
```

